let estado = String(msg.payload).trim();
let agora = new Date();

let funcionario = "Débora da Silva Costa";
let epi = "Capacete 01";

// PADRÃO DO SEU PROJETO ATUAL:
// DETECTOU = capacete na cabeça = ATIVO
// LIVRE = capacete fora da cabeça = INATIVO
// Se ficar invertido, troque DETECTOU por LIVRE na linha abaixo.
let statusAtual = estado === "LIVRE" ? "ATIVO" : "INATIVO";

let ultimoEstado = flow.get("ultimoEstadoSensor");
let ultimoTempo = flow.get("ultimoTempoSensor") || Date.now();

if (ultimoEstado === undefined) {
    flow.set("ultimoEstadoSensor", estado);
    flow.set("ultimoTempoSensor", Date.now());

    let inicial = criarRegistro(statusAtual, agora, agora, 0, "Estado inicial: " + statusAtual);
    msg.payload = montarPainel(inicial);
    return [msg, null];
}

if (estado !== ultimoEstado) {
    let inicio = new Date(ultimoTempo);
    let fim = agora;
    let tempoSegundos = Math.floor((fim - inicio) / 1000);

    let statusAnterior = ultimoEstado === "LIVRE" ? "ATIVO" : "INATIVO";
    let registro = criarRegistro(statusAnterior, inicio, fim, tempoSegundos, "");

    let historico = flow.get("historicoCapacete") || [];
    historico.unshift(registro);
    if (historico.length > 500) historico = historico.slice(0, 500);
    flow.set("historicoCapacete", historico);

    flow.set("ultimoEstadoSensor", estado);
    flow.set("ultimoTempoSensor", Date.now());

    msg.payload = montarPainel(registro);

    let linhaCSV =
        registro.funcionario + ";" +
        registro.epi + ";" +
        registro.data + ";" +
        registro.horaInicio + ";" +
        registro.horaFim + ";" +
        registro.status + ";" +
        registro.tempoSegundos + ";" +
        registro.tempo + ";" +
        registro.descricao;

    return [msg, {payload: linhaCSV}];
}

let atual = criarRegistro(statusAtual, agora, agora, 0, "Sem mudança de estado");
msg.payload = montarPainel(atual);
return [msg, null];

function criarRegistro(status, inicio, fim, segundos, descricaoCustom) {
    let min = Math.floor(segundos / 60);
    let seg = segundos % 60;
    let tempo = min + " min " + seg + " seg";
    let descricao = descricaoCustom || ("Ficou " + status + " por " + tempo);

    return {
        funcionario: funcionario,
        epi: epi,
        data: fim.toLocaleDateString("pt-BR"),
        horaInicio: inicio.toLocaleTimeString("pt-BR"),
        horaFim: fim.toLocaleTimeString("pt-BR"),
        status: status,
        tempoSegundos: segundos,
        tempo: tempo,
        descricao: descricao,
        valor: status === "ATIVO" ? 1 : 0,
        alarme: status === "INATIVO" ? "⚠ SEM CAPACETE" : "✅ CAPACETE EM USO"
    };
}

function montarPainel(ultimo) {
    let historico = flow.get("historicoCapacete") || [];
    return {
        ultimo: ultimo,
        resumo: resumo(historico),
        historico: historico
    };
}

function resumo(h) {
    let ativo = 0;
    let inativo = 0;
    let alertas = 0;

    for (let r of h) {
        let t = Number(r.tempoSegundos || 0);
        if (r.status === "ATIVO") ativo += t;
        if (r.status === "INATIVO") {
            inativo += t;
            alertas++;
        }
    }

    let total = ativo + inativo;
    let conformidade = total > 0 ? Math.round((ativo / total) * 100) : 0;

    return {
        tempoAtivo: formatar(ativo),
        tempoInativo: formatar(inativo),
        conformidade: conformidade,
        totalEventos: h.length,
        totalAlertas: alertas
    };
}

function formatar(s) {
    let h = Math.floor(s / 3600);
    let m = Math.floor((s % 3600) / 60);
    let sec = s % 60;
    if (h > 0) return h + "h " + m + "min";
    return m + " min " + sec + " seg";
}
